12	/**
13	 * Joins the given base URL and path, ensuring that there is only one slash between them.
14	 */
15	export function joinURL(base?: string, path?: string): string {
16	  if (!base || base === "/") {
17	    return path || "/";
18	  }
19	
20	  if (!path || path === "/") {
21	    return base || "/";
22	  }
23	
24	  const baseHasTrailing = base[base.length - 1] === "/";
25	  const pathHasLeading = path[0] === "/";
26	  if (baseHasTrailing && pathHasLeading) {
27	    return base + path.slice(1);
28	  }
29	
30	  if (!baseHasTrailing && !pathHasLeading) {
31	    return `${base}/${path}`;
32	  }
33	
34	  return base + path;
35	}
