// Default failure statuses that count against an origin's circuit.
// https://developer.mozilla.org/en-US/docs/Web/HTTP/Status
const DEFAULT_FAILURE_STATUS_CODES = [408, 409, 425, 429, 500, 502, 503, 504];

export type CircuitStatus = "closed" | "open" | "half-open";

export interface CircuitState {
  status: CircuitStatus;
  /** Consecutive failures while closed. */
  failures: number;
  /** `Date.now()` when the circuit last opened (cooldown anchor). */
  openedAt: number;
  /** Number of in-flight half-open probes. */
  halfOpenActive: number;
}

/** Per-origin circuit state, shared between clients derived via `.create()`. */
export type CircuitStore = Map<string, CircuitState>;

/** Fully-resolved circuit breaker configuration. */
export interface CircuitBreakerConfig {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

/**
 * Per logical-request circuit bookkeeping. A single object is shared across a
 * request and all of its internal retries so that one external call is only
 * ever accounted once and a half-open probe keeps its slot for the whole life
 * of the logical request.
 */
export interface CircuitRun {
  config: CircuitBreakerConfig;
  origin: string;
  /** True when this logical request holds a half-open probe slot. */
  probeHeld: boolean;
  /** True once the logical request outcome has been recorded. */
  finalized: boolean;
}

/** Marker used to carry the {@link CircuitRun} across internal retries. */
export const CIRCUIT = Symbol("ofetch.circuit");

/**
 * Resolve the request `circuitBreaker` option into a full config, applying the
 * documented defaults. Returns `undefined` when circuit tracking is disabled.
 */
export function resolveCircuitOptions(
  input: boolean | CircuitBreakerOptions | undefined
): CircuitBreakerConfig | undefined {
  if (!input) {
    return undefined;
  }
  if (input === true) {
    return {
      threshold: 5,
      cooldown: 30_000,
      halfOpenMaxRequests: 1,
      failureStatusCodes: [...DEFAULT_FAILURE_STATUS_CODES],
    };
  }
  return {
    threshold: input.threshold ?? 5,
    cooldown: input.cooldown ?? 30_000,
    halfOpenMaxRequests: input.halfOpenMaxRequests ?? 1,
    failureStatusCodes: input.failureStatusCodes
      ? [...input.failureStatusCodes]
