    return "probe";
  }

  return "ok";
}

/** Record a successful logical request: reset streak and close the circuit. */
export function recordSuccess(store: CircuitStore, run: CircuitRun): void {
  const state = store.get(run.origin);
  if (!state) {
    return;
  }
  state.failures = 0;
  state.status = "closed";
}

/**
 * Record a failed logical request. A failing half-open probe reopens the
 * circuit and restarts the cooldown from the failure time; otherwise the
 * consecutive-failure streak advances and may trip the circuit open.
